import{_ as o,o as s,c as e,a0 as n}from"./chunks/framework.jwovEGr5.js";const g=JSON.parse('{"title":"🏪 賣家管理與更名指南","description":"","frontmatter":{},"headers":[],"relativePath":"Shop-Management.md","filePath":"Shop-Management.md"}'),l={name:"Shop-Management.md"};function t(i,a,r,p,c,d){return s(),e("div",null,[...a[0]||(a[0]=[n(`<h1 id="🏪-賣家管理與更名指南" tabindex="-1">🏪 賣家管理與更名指南 <a class="header-anchor" href="#🏪-賣家管理與更名指南" aria-label="Permalink to &quot;🏪 賣家管理與更名指南&quot;">​</a></h1><p>本章節介紹商店主人（賣家）如何管理自己名下的所有商店，包含使用 <code>/shop</code> 圖形選單、遠端提領營收、自訂商店名稱，以及設定大宗批發模式。</p><hr><h2 id="_1-🏪-商店瀏覽與管理選單-shop" tabindex="-1">1. 🏪 商店瀏覽與管理選單 (<code>/shop</code>) <a class="header-anchor" href="#_1-🏪-商店瀏覽與管理選單-shop" aria-label="Permalink to &quot;1. 🏪 商店瀏覽與管理選單 (\`/shop\`)&quot;">​</a></h2><p>玩家可以在遊戲內輸入 <strong><code>/shop</code></strong> 開啟全伺服器的商店管理選單：</p><ul><li><strong>商店名錄</strong>：介面會列出伺服器中所有的商店。將游標移至商品上，可查看： <ul><li>商店主人名稱</li><li>商店自訂名稱（若已設定）</li><li>商品出售與收購價格</li><li>商店箱子剩餘庫存</li><li>商店位置座標 (X, Y, Z) 與世界維度</li><li>商店平均評分</li></ul></li><li><strong>商品過濾篩選 <code>/shop search &lt;物品名稱&gt;</code></strong>： <ul><li>當商店數量眾多時，玩家可輸入此指令進行篩選（亦可使用中文指令 <code>/shop 搜尋 &lt;物品名稱&gt;</code>）。</li><li>系統會自動過濾出僅包含該物品的商店，並自動將價格最便宜的商店排列在最前面，方便進行比價。</li></ul></li></ul><hr><h2 id="🖱️-2-店主專屬告示牌控制面板-owner-chat-gui" tabindex="-1">🖱️ 2. 店主專屬告示牌控制面板 (Owner Chat GUI) <a class="header-anchor" href="#🖱️-2-店主專屬告示牌控制面板-owner-chat-gui" aria-label="Permalink to &quot;🖱️ 2. 店主專屬告示牌控制面板 (Owner Chat GUI)&quot;">​</a></h2><p>店主對著自己名下商店的<strong>告示牌 (Sign)</strong> 按下**【右鍵】<strong>時，會直接在個人聊天欄開啟專屬的</strong>店主控制面板**：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>§6=================== 商店管理 ===================</span></span>
<span class="line"><span>§f商店座標: 100, 64, -200 (minecraft:overworld)</span></span>
<span class="line"><span>§f無限模式: 停用 [修改]</span></span>
<span class="line"><span>§f商店模式: 出售 [修改]</span></span>
<span class="line"><span>§f價格設定: 售 $100.0 | 收 $0.0 [修改]</span></span>
<span class="line"><span>§f遠端補貨: 補滿商品 [執行]</span></span>
<span class="line"><span>§f清空商品: 清空箱子 [執行]</span></span>
<span class="line"><span>§f懸浮展示: 啟用 [切換]</span></span>
<span class="line"><span>§f交易歷史: 查看日誌 [查看]</span></span>
<span class="line"><span>§c[刪除商店] (點擊註銷此商店)</span></span>
<span class="line"><span>§6============================================</span></span></code></pre></div><h3 id="控制項功能說明" tabindex="-1">控制項功能說明： <a class="header-anchor" href="#控制項功能說明" aria-label="Permalink to &quot;控制項功能說明：&quot;">​</a></h3><ul><li><strong>無限模式 (Infinite Mode)</strong>：點選 <code>[修改]</code> 可將商店設定為無限商店（限管理員或特許帳號啟用）。啟用後，庫存與收購金幣均變為無限。</li><li><strong>商店模式</strong>：點選 <code>[修改]</code> 可在 <code>出售</code>、<code>收購</code> 與 <code>雙向（既出售又收購）</code> 模式間進行切換。</li><li><strong>價格設定</strong>：點選 <code>[修改]</code> 會進入定價輸入模式，依序在聊天欄輸入新的出售單價與收購單價即可完成設定。</li><li><strong>遠端補貨/清空</strong>： <ul><li><em>限制</em>：<strong>僅限「無限模式」商店與管理員執行</strong>。</li><li>點選 <code>[執行]</code> 可一鍵補滿或清空箱子內該商品的數量。普通生存商店必須由店主親自前往箱子位置放入或取回商品。</li></ul></li><li><strong>懸浮展示</strong>：點選 <code>[切換]</code> 可開啟或隱藏箱子正上方的懸浮商品模型。</li><li><strong>交易歷史</strong>：點選 <code>[查看]</code> 可直接在聊天欄顯示該商店最近的交易歷史。</li><li><strong>刪除商店</strong>：點選 <code>[刪除商店]</code> 可直接註銷商店。告示牌文字將會清空並收回懸浮展示物。</li></ul><hr><h2 id="_3-💰-商店升級與帳務管理" tabindex="-1">3. 💰 商店升級與帳務管理 <a class="header-anchor" href="#_3-💰-商店升級與帳務管理" aria-label="Permalink to &quot;3. 💰 商店升級與帳務管理&quot;">​</a></h2><h3 id="a-商店槽位升級-shop-upgrade" tabindex="-1">A. 商店槽位升級 (<code>/shop upgrade</code>) <a class="header-anchor" href="#a-商店槽位升級-shop-upgrade" aria-label="Permalink to &quot;A. 商店槽位升級 (\`/shop upgrade\`)&quot;">​</a></h3><p>每位玩家預設最多可建立 15 個商店。</p><ol><li>在遊戲內輸入 <strong><code>/shop upgrade</code></strong>。</li><li>系統會扣除玩家個人帳戶的 <strong>$5,000 遊戲金幣</strong>，並永久增加 <strong>1 個</strong> 商店建立上限。</li></ol><h3 id="b-商店付費更名-shop-rename" tabindex="-1">B. 商店付費更名 (<code>/shop rename</code>) <a class="header-anchor" href="#b-商店付費更名-shop-rename" aria-label="Permalink to &quot;B. 商店付費更名 (\`/shop rename\`)&quot;">​</a></h3><ol><li>在遊戲內輸入指令：<strong><code>/shop rename &lt;座標&gt; &lt;自訂名稱&gt;</code></strong>。 <ul><li><em>範例</em>：<code>/shop rename 100,64,-200 礦產大帝鑽石店</code></li></ul></li><li><strong>更名限制</strong>：名稱長度不能超過 15 個字，且需要支付 <strong>$5,000 手續費</strong>。</li><li>更名成功後，告示牌第二行與 <code>/shop</code> 選單名錄中將同步顯示為該自訂名稱。</li></ol><h3 id="c-商家交易日誌-shop-logs" tabindex="-1">C. 商家交易日誌 (<code>/shop logs</code>) <a class="header-anchor" href="#c-商家交易日誌-shop-logs" aria-label="Permalink to &quot;C. 商家交易日誌 (\`/shop logs\`)&quot;">​</a></h3><ol><li>在遊戲內輸入 <strong><code>/shop logs</code></strong>。</li><li>聊天欄會顯示該商家最近的 <strong>20 筆真實成交日誌</strong>，包含買家名稱、交易時間、商品數量與扣稅後的實得營收。</li><li><strong>Discord 即時同步</strong>：交易完成的當下，日誌會即時同步發送到您綁定的 Discord 頻道，讓您在 Discord 上也能即時追蹤營收！</li></ol>`,21)])])}const u=o(l,[["render",t]]);export{g as __pageData,u as default};
